import clsx from 'clsx';

import Spacings from '@dynatrace/strato-design-tokens/spacings';

import { formattedTimeframe } from './TimeFrameHeader.sty.js';
import { DurationChipAtom } from '../../../../tooltip-atoms/components/DurationChipAtom/DurationChipAtom.js';
import { TooltipItem } from '../../../section-components/TooltipItem/TooltipItem.js';
import { FormattedTimeframe } from '../../../utils/FormattedTimeframe.js';

/** @internal */
export interface TimeFrameHeaderProps {
  from: Date;
  to: Date;
  showDuration?: boolean;
  limit?: number;
  clampFutureToDateToNow?: boolean;
  className?: string;
}

/** @internal */
export const TimeFrameHeader = ({
  from,
  to,
  showDuration,
  limit,
  clampFutureToDateToNow,
  className,
}: TimeFrameHeaderProps) => {
  return (
    <TooltipItem>
      {showDuration && (
        <DurationChipAtom
          from={from}
          to={to}
          limit={limit}
          style={{ marginRight: Spacings.Size4 }}
          className={clsx(className)}
        />
      )}
      <FormattedTimeframe
        from={from}
        to={to}
        clampFutureToDateToNow={clampFutureToDateToNow}
        className={formattedTimeframe}
      />
    </TooltipItem>
  );
};

TimeFrameHeader['displayName'] = 'ChartTooltip.TimeFrameHeader';
